import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.OsDJF_Ea.js";const u=JSON.parse('{"title":"The Hardware","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/hardware.md","filePath":"getting-started/hardware.md"}'),s={name:"getting-started/hardware.md"};function n(d,t,i,h,l,p){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="the-hardware" tabindex="-1">The Hardware <a class="header-anchor" href="#the-hardware" aria-label="Permalink to &quot;The Hardware&quot;">​</a></h1><p>The Smart Contact Mic hardware provides hands-on control over your patches. Here&#39;s what each physical control does and how it maps to your patch.</p><h2 id="controls-overview" tabindex="-1">Controls Overview <a class="header-anchor" href="#controls-overview" aria-label="Permalink to &quot;Controls Overview&quot;">​</a></h2><p>The SCM is a minimal board with no physical controls on-board. All parameter control comes from:</p><ul><li><strong>USB MIDI</strong> -- Send CC and note messages from a DAW or MIDI controller</li><li><strong>Breakout headers</strong> -- Connect external pots, buttons, or I2C peripherals</li></ul><h2 id="banking-system" tabindex="-1">Banking System <a class="header-anchor" href="#banking-system" aria-label="Permalink to &quot;Banking System&quot;">​</a></h2><p>With only 4 pots and 4 buttons, complex patches need more controls. The banking system solves this -- the encoder switches between 6 banks, each giving the pots and buttons a different assignment.</p><p><strong>Bank colours:</strong></p><table tabindex="0"><thead><tr><th>Bank</th><th>Colour</th></tr></thead><tbody><tr><td>1</td><td>Red</td></tr><tr><td>2</td><td>Green</td></tr><tr><td>3</td><td>Blue</td></tr><tr><td>4</td><td>Yellow</td></tr><tr><td>5</td><td>Cyan</td></tr><tr><td>6</td><td>Magenta</td></tr></tbody></table><p>Turn the encoder to switch banks. The NeoPixels flash the bank colour briefly to confirm.</p><h3 id="soft-takeover" tabindex="-1">Soft Takeover <a class="header-anchor" href="#soft-takeover" aria-label="Permalink to &quot;Soft Takeover&quot;">​</a></h3><p>When you switch banks, the pots don&#39;t jump to the new bank&#39;s values immediately. Instead, the output stays at the stored value until the physical pot position crosses within 5% of where the software expects it. This prevents sudden jumps when switching banks.</p><h3 id="auto-mapped-modules" tabindex="-1">Auto-Mapped Modules <a class="header-anchor" href="#auto-mapped-modules" aria-label="Permalink to &quot;Auto-Mapped Modules&quot;">​</a></h3><p>Some modules (Stereo Mixer, Drum Machine, BPM Looper, and others) automatically claim one or two banks and pre-assign their pots and buttons. These modules show a coloured footer on the canvas indicating which bank(s) they use.</p><p>Pot and Button modules you add manually are assigned to the next available bank.</p><h2 id="audio" tabindex="-1">Audio <a class="header-anchor" href="#audio" aria-label="Permalink to &quot;Audio&quot;">​</a></h2><p>The SCM uses an <strong>ES8311 mono codec</strong> for both input and output. It&#39;s designed for contact mic applications -- the built-in piezo preamp amplifies contact mic signals with a differential input stage.</p><table tabindex="0"><thead><tr><th>Signal</th><th>Description</th></tr></thead><tbody><tr><td>Audio In</td><td>Mono piezo input via TLV9064 differential preamp</td></tr><tr><td>Audio Out</td><td>Mono output via ES8311 DAC</td></tr><tr><td>Speaker</td><td>NS4150B 3W amplifier for small speakers</td></tr></tbody></table><h2 id="power" tabindex="-1">Power <a class="header-anchor" href="#power" aria-label="Permalink to &quot;Power&quot;">​</a></h2><p>The board is powered over USB-C. Use a quality USB power supply or laptop port. Avoid unpowered USB hubs for best stability.</p><h2 id="sd-card" tabindex="-1">SD Card <a class="header-anchor" href="#sd-card" aria-label="Permalink to &quot;SD Card&quot;">​</a></h2><p>A micro SD card slot provides storage for samples, recordings, and multi-sample banks. Format the card as FAT32.</p>',22)])])}const m=e(s,[["render",n]]);export{u as __pageData,m as default};
